<?php
 namespace WPAICG\Core\Providers\OpenRouter\Methods; use WPAICG\Core\Providers\OpenRouterProviderStrategy; use WPAICG\Core\Providers\OpenRouter\OpenRouterPayloadFormatter; use WP_Error; if (!defined('ABSPATH')) { exit; } function format_chat_payload_logic( OpenRouterProviderStrategy $strategyInstance, string $user_message, string $instructions, array $history, array $ai_params, string $model ): array { if (!class_exists(\WPAICG\Core\Providers\OpenRouter\OpenRouterPayloadFormatter::class)) { $formatter_bootstrap = dirname(__FILE__) . '/bootstrap-payload-formatter.php'; if (file_exists($formatter_bootstrap)) { require_once $formatter_bootstrap; } else { return []; } } $final_history = $history; if (!empty($user_message)) { $last_msg = end($final_history); if (!$last_msg || $last_msg['role'] !== 'user' || $last_msg['content'] !== $user_message) { $final_history[] = ['role' => 'user', 'content' => $user_message]; } } return \WPAICG\Core\Providers\OpenRouter\OpenRouterPayloadFormatter::format_chat($instructions, $final_history, $ai_params, $model); }